"use client";

import { create } from "zustand";

import {
  createClientGameSession,
  type ClientGameSession,
  type ClientGameSessionStep,
} from "@/input/game-session";
import type { RunAction } from "@engine/run";
import type { GameState } from "@engine/state";

export type ContextPanelMode = "inspect" | "inventory" | "quest" | "dialogue";

export type PendingConfirm = {
  readonly action: RunAction;
  readonly prompt: string;
};

export type InputFeedbackActionKind = Exclude<RunAction["kind"], "take_hoard">;

export type UiSlice = {
  readonly contextPanelMode: ContextPanelMode;
  readonly diaryOpen: boolean;
  readonly artifactOpen: boolean;
  readonly keymapOpen: boolean;
  readonly pendingConfirm: PendingConfirm | null;
  readonly inputLocked: boolean;
};

export type GameStore = {
  readonly gameState: GameState | null;
  readonly gameSession: ClientGameSession | null;
  readonly ui: UiSlice;
  readonly startGameSession: (options: { readonly seed: string }) => void;
  readonly setGameState: (state: GameState) => void;
  readonly dispatchAction: (action: RunAction) => ClientGameSessionStep | null;
  readonly appendInputFeedback: (
    actionKind: InputFeedbackActionKind,
    reason: string,
  ) => void;
  readonly setInputLocked: (inputLocked: boolean) => void;
  readonly patchUi: (patch: Partial<UiSlice>) => void;
};

export const defaultUi: UiSlice = {
  contextPanelMode: "inspect",
  diaryOpen: false,
  artifactOpen: false,
  keymapOpen: false,
  pendingConfirm: null,
  inputLocked: false,
};

export const useGameStore = create<GameStore>((set, get) => ({
  gameState: null,
  gameSession: null,
  ui: defaultUi,
  startGameSession: ({ seed }) => {
    const gameSession = createClientGameSession({ seed });
    set({
      gameSession,
      gameState: gameSession.state,
      ui: defaultUi,
    });
  },
  setGameState: (gameState) =>
    set((current) => {
      current.gameSession?.replaceState(gameState);
      return { gameState };
    }),
  dispatchAction: (action) => {
    const session = get().gameSession;
    if (session === null) {
      return null;
    }

    const result = session.step(action);
    set({ gameState: result.state });
    return result;
  },
  appendInputFeedback: (actionKind, reason) =>
    set((current) => {
      if (current.gameState === null) {
        return {};
      }

      const event = {
        turn: current.gameState.run.turn,
        type: "action_illegal",
        data: {
          actionKind,
          reason,
        },
      } as const satisfies GameState["log"][number];
      const gameState = {
        ...current.gameState,
        log: [...current.gameState.log, event],
      };

      current.gameSession?.replaceState(gameState);

      return { gameState };
    }),
  setInputLocked: (inputLocked) =>
    set((current) => ({
      ui: { ...current.ui, inputLocked },
    })),
  patchUi: (patch) =>
    set((current) => ({
      ui: { ...current.ui, ...patch },
    })),
}));

import { chebyshevDistance } from "@engine/map";
import type { RunAction } from "@engine/run";
import type { EntityInstance, GameState } from "@engine/state";
import { checkActionLegality, type PlayerAction } from "@engine/turn";

import {
  resolveKeyBinding,
  type KeyBindingContext,
  type KeyIntent,
} from "./keys";
import { autoTravelStopFor } from "./travel";
import type {
  InputFeedbackActionKind,
  PendingConfirm,
  UiSlice,
} from "@/store/game-store";

export type GameKeyPress = {
  readonly key: string;
  readonly repeat?: boolean;
};

export type InputDispatchResult =
  | {
      readonly status: "ignored";
      readonly reason: string;
      readonly preventDefault: false;
    }
  | {
      readonly status: "handled";
      readonly intent: KeyIntent["kind"];
      readonly preventDefault: true;
    }
  | {
      readonly status: "action_dispatched";
      readonly action: RunAction;
      readonly preventDefault: true;
    }
  | {
      readonly status: "confirm_required";
      readonly confirm: PendingConfirm;
      readonly preventDefault: true;
    }
  | {
      readonly status: "travel_stopped";
      readonly reason: string;
      readonly preventDefault: true;
    }
  | {
      readonly status: "input_locked";
      readonly preventDefault: true;
    };

export type InputDispatchSnapshot = {
  readonly gameState: GameState | null;
  readonly ui: UiSlice;
};

export type InputDispatchDeps = {
  readonly dispatchAction: (action: RunAction) => void;
  readonly patchUi: (patch: Partial<UiSlice>) => void;
  readonly appendInputFeedback: (
    actionKind: InputFeedbackActionKind,
    reason: string,
  ) => void;
  readonly lockInput: () => void;
};

export const dispatchGameKey = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
  keyPress: GameKeyPress,
): InputDispatchResult => {
  const context = inputFocusContext(snapshot.ui);
  const binding = resolveKeyBinding(keyPress.key, context);

  if (binding === null) {
    return {
      status: "ignored",
      reason: `unbound key in ${context}`,
      preventDefault: false,
    };
  }

  const intent = binding.intent;

  if (
    snapshot.ui.inputLocked &&
    intent.kind === "run_action"
  ) {
    return { status: "input_locked", preventDefault: true };
  }

  switch (intent.kind) {
    case "run_action":
      return dispatchRunAction(snapshot, deps, intent.action, keyPress);
    case "set_context_mode":
      deps.patchUi({
        contextPanelMode:
          snapshot.ui.contextPanelMode === intent.mode ? "inspect" : intent.mode,
      });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "toggle_diary":
      deps.patchUi({
        diaryOpen: !snapshot.ui.diaryOpen,
        artifactOpen: false,
      });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "open_keymap":
      deps.patchUi({ keymapOpen: true });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "close_keymap":
      deps.patchUi({ keymapOpen: false });
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "close_top":
      closeTop(snapshot, deps);
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
    case "confirm_yes":
      return confirmPending(snapshot, deps);
    case "confirm_no":
      cancelPendingConfirm(snapshot, deps);
      return {
        status: "handled",
        intent: intent.kind,
        preventDefault: true,
      };
  }
};

export const inputFocusContext = (ui: UiSlice): KeyBindingContext => {
  if (ui.keymapOpen) {
    return "overlay";
  }

  if (ui.diaryOpen || ui.artifactOpen) {
    return "paused-layer";
  }

  if (ui.pendingConfirm !== null) {
    return "confirm";
  }

  return "play";
};

export const dangerousConfirmForAction = (
  state: GameState,
  action: RunAction,
): PendingConfirm | null => {
  if (action.kind !== "descend" || !isPlayerAction(action)) {
    return null;
  }

  const legality = checkActionLegality(state, action);
  if (legality.status === "illegal") {
    return null;
  }

  const adjacentEnemy = adjacentEnemies(state)[0];
  if (adjacentEnemy === undefined) {
    return null;
  }

  return {
    action,
    prompt: `Enemy ${adjacentEnemy.id} is adjacent. Descend anyway? y/n`,
  };
};

const dispatchRunAction = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
  action: RunAction,
  keyPress: GameKeyPress,
): InputDispatchResult => {
  if (snapshot.gameState === null) {
    return {
      status: "ignored",
      reason: "game state not ready",
      preventDefault: false,
    };
  }

  if (keyPress.repeat === true && action.kind !== "move") {
    return {
      status: "ignored",
      reason: "non-move key repeat ignored",
      preventDefault: false,
    };
  }

  if (keyPress.repeat === true && action.kind === "move") {
    const stop = autoTravelStopFor(snapshot.gameState);
    if (stop !== null) {
      deps.appendInputFeedback("move", stop.message);
      return {
        status: "travel_stopped",
        reason: stop.reason,
        preventDefault: true,
      };
    }
  }

  const confirm = dangerousConfirmForAction(snapshot.gameState, action);
  if (confirm !== null) {
    deps.patchUi({ pendingConfirm: confirm });
    return {
      status: "confirm_required",
      confirm,
      preventDefault: true,
    };
  }

  deps.dispatchAction(action);
  deps.lockInput();

  return {
    status: "action_dispatched",
    action,
    preventDefault: true,
  };
};

const confirmPending = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
): InputDispatchResult => {
  const pending = snapshot.ui.pendingConfirm;
  if (pending === null) {
    return {
      status: "ignored",
      reason: "no pending confirm",
      preventDefault: false,
    };
  }

  deps.patchUi({ pendingConfirm: null });
  deps.dispatchAction(pending.action);
  deps.lockInput();

  return {
    status: "action_dispatched",
    action: pending.action,
    preventDefault: true,
  };
};

const closeTop = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
): void => {
  if (snapshot.ui.keymapOpen) {
    deps.patchUi({ keymapOpen: false });
    return;
  }

  if (snapshot.ui.pendingConfirm !== null) {
    cancelPendingConfirm(snapshot, deps);
    return;
  }

  if (snapshot.ui.diaryOpen || snapshot.ui.artifactOpen) {
    deps.patchUi({ diaryOpen: false, artifactOpen: false });
    return;
  }

  if (snapshot.ui.contextPanelMode !== "inspect") {
    deps.patchUi({ contextPanelMode: "inspect" });
  }
};

const cancelPendingConfirm = (
  snapshot: InputDispatchSnapshot,
  deps: InputDispatchDeps,
): void => {
  const pending = snapshot.ui.pendingConfirm;
  deps.patchUi({ pendingConfirm: null });

  if (pending !== null && isInputFeedbackActionKind(pending.action.kind)) {
    deps.appendInputFeedback(pending.action.kind, "Cancelled.");
  }
};

const adjacentEnemies = (state: GameState): readonly EntityInstance[] =>
  Object.values(state.entities)
    .filter((entity) => entity.kind === "enemy")
    .filter(
      (entity) =>
        chebyshevDistance(state.player.position, entity.position) <= 1,
    )
    .sort((left, right) => left.id.localeCompare(right.id));

const isPlayerAction = (action: RunAction): action is PlayerAction =>
  action.kind !== "take_hoard";

const isInputFeedbackActionKind = (
  kind: RunAction["kind"],
): kind is InputFeedbackActionKind => kind !== "take_hoard";

"use client";

import "@/api/director/engine-runtime-web";

import { createFallbackFloorContentProvider } from "@/api/director/fallback-provider-web";
import {
  dialogueTurnHooks,
  freezeTurnCount,
  isWorldPaused,
} from "@engine/npc";
import {
  startRun,
  stepRun,
  type FloorContentProvider,
  type RunAction,
  type RunLoopResult,
} from "@engine/run";
import type { GameState } from "@engine/state";

type RunEvent = Extract<RunLoopResult, { readonly ok: true }>["events"][number];

export type ClientGameSessionStep = {
  readonly state: GameState;
  readonly events: readonly RunEvent[];
};

export type ClientGameSession = {
  readonly state: GameState;
  readonly step: (action: RunAction) => ClientGameSessionStep;
  readonly replaceState: (state: GameState) => void;
};

export type ClientGameSessionOptions = {
  readonly seed: string;
  readonly provider?: FloorContentProvider;
};

export const createClientGameSession = ({
  seed,
  provider = createFallbackFloorContentProvider(),
}: ClientGameSessionOptions): ClientGameSession => {
  const started = startRun(seed, provider);
  if (!started.ok) {
    throw new Error(started.error.message);
  }

  let state = started.state;

  return {
    get state() {
      return state;
    },
    step: (action) => {
      const before = state;
      const result = stepPlayerAction(before, action, provider);
      if (!result.ok) {
        throw new Error(result.error.message);
      }

      state = appendMissingReturnedEvents(before, result.state, result.events);

      return {
        state,
        events: result.events,
      };
    },
    replaceState: (nextState) => {
      state = nextState;
    },
  };
};

const stepPlayerAction = (
  state: GameState,
  action: RunAction,
  provider: FloorContentProvider,
): RunLoopResult => {
  const turnBefore = state.run.turn;
  const result = stepRun(state, action, provider, {
    hooks: dialogueTurnHooks(),
  });

  if (!result.ok) {
    return result;
  }

  let nextState = result.state;
  const events = [...result.events];

  if (action.kind === "talk" || isWorldPaused(state) || isWorldPaused(nextState)) {
    nextState = freezeTurnCount(nextState, turnBefore);
  }

  return {
    ok: true,
    state: nextState,
    events,
  };
};

const appendMissingReturnedEvents = (
  before: GameState,
  after: GameState,
  events: readonly RunEvent[],
): GameState => {
  const appendedCount = Math.max(0, after.log.length - before.log.length);
  if (appendedCount >= events.length) {
    return after;
  }

  return {
    ...after,
    log: [...after.log, ...events.slice(appendedCount)],
  };
};

"use client";

import { useEffect, useRef } from "react";

import { useGameStore } from "@/store/game-store";

import {
  dispatchGameKey,
  type InputDispatchDeps,
} from "./dispatcher";

const INPUT_LOCK_MS = 50;

export function GameInputOwner() {
  useGameInputOwner();
  return null;
}

export const useGameInputOwner = (): void => {
  const unlockTimer = useRef<number | null>(null);

  useEffect(() => {
    const unlock = (): void => {
      if (unlockTimer.current !== null) {
        window.clearTimeout(unlockTimer.current);
        unlockTimer.current = null;
      }

      useGameStore.getState().setInputLocked(false);
    };

    const lockInput = (): void => {
      useGameStore.getState().setInputLocked(true);
      if (unlockTimer.current !== null) {
        window.clearTimeout(unlockTimer.current);
      }

      unlockTimer.current = window.setTimeout(unlock, INPUT_LOCK_MS);
    };

    const onKeyDown = (event: KeyboardEvent): void => {
      if (event.defaultPrevented || isEditableTarget(event.target)) {
        return;
      }

      const store = useGameStore.getState();
      const deps: InputDispatchDeps = {
        dispatchAction: store.dispatchAction,
        patchUi: store.patchUi,
        appendInputFeedback: store.appendInputFeedback,
        lockInput,
      };
      const result = dispatchGameKey(
        {
          gameState: store.gameState,
          ui: store.ui,
        },
        deps,
        {
          key: event.key,
          repeat: event.repeat,
        },
      );

      if (result.preventDefault) {
        event.preventDefault();
      }
    };

    window.addEventListener("keydown", onKeyDown);

    return () => {
      window.removeEventListener("keydown", onKeyDown);
      unlock();
    };
  }, []);
};

const isEditableTarget = (target: EventTarget | null): boolean => {
  if (!(target instanceof HTMLElement)) {
    return false;
  }

  if (target.isContentEditable) {
    return true;
  }

  const tagName = target.tagName.toLowerCase();

  return tagName === "input" || tagName === "textarea" || tagName === "select";
};

import type { RunAction } from "@engine/run";
