export const normalizeKeyboardKey = (key: string): string =>
  key === "\u001b" ? "Escape" : key;

export const resolveKeyBinding = (
  key: string,
  context: KeyBindingContext,
): KeymapBinding | null => {
  const normalized = normalizeKeyboardKey(key);

  return (
    KEYMAP_BINDINGS.find(
      (binding) =>
        binding.contexts.includes(context) &&
        binding.keys.includes(normalized),
    ) ?? null
  );
};

export const keymapOverlayRows = (): readonly KeymapOverlayRow[] =>
  KEYMAP_BINDINGS.filter((binding) => binding.showInOverlay !== false).map(
    (binding) => ({
      id: binding.id,
      group: binding.helpGroup,
      action: binding.helpAction,
      keys: binding.keyLabel,
    }),
  );

export const keymapOverlayGroups = (): readonly KeymapBinding["helpGroup"][] => [
  "Movement",
  "Actions",
  "Panels",
  "Universal",
];

"use client";

import { useGameStore } from "@/store/game-store";
import { GridRegion } from "@/components/grid";
import { HudRegion } from "@/components/hud";
import { KeymapOverlay } from "@/components/keymap-overlay/KeymapOverlay";
import { MessageLogRegion } from "@/components/log";
import { GameInputOwner } from "@/input";
import { InlineConfirmPrompt } from "@/input/InlineConfirmPrompt";

const regionClass =
  "rounded border border-gg-border bg-gg-surface text-gg-muted flex items-center justify-center text-sm uppercase tracking-wide";
const gridRegionClass = "min-h-0";

export function GameShell() {
  const gameState = useGameStore((state) => state.gameState);
  const ui = useGameStore((state) => state.ui);

  return (
    <main className="grid h-screen grid-rows-[minmax(0,1fr)_7rem] gap-2 overflow-hidden p-3">
      <GameInputOwner />
      <div className="grid min-h-0 grid-cols-[minmax(0,1fr)_minmax(18rem,24rem)] gap-2">
