import type {
  EntityId,
  EntityInstance,
  GameState,
  InventorySlot,
  Position,
  SerializableRecord,
} from "../state/index.js";
import {
  chebyshevDistance,
  getTile,
  inBounds,
  isWalkableTile,
  Terrain,
  type TileGrid,
} from "../map/index.js";

export const MOVE_DIRECTIONS = [
  { direction: "northwest", offset: { x: -1, y: -1 } },
  { direction: "north", offset: { x: 0, y: -1 } },
  { direction: "northeast", offset: { x: 1, y: -1 } },
  { direction: "west", offset: { x: -1, y: 0 } },
  { direction: "east", offset: { x: 1, y: 0 } },
  { direction: "southwest", offset: { x: -1, y: 1 } },
  { direction: "south", offset: { x: 0, y: 1 } },
  { direction: "southeast", offset: { x: 1, y: 1 } },
] as const;

export type MoveDirection = (typeof MOVE_DIRECTIONS)[number]["direction"];

export type ActionTarget =
  | {
      readonly kind: "self";
    }
  | {
      readonly kind: "entity";
      readonly entityId: EntityId;
    }
  | {
      readonly kind: "cell";
      readonly cell: Position;
    };

export type MoveAction = {
  readonly kind: "move";
  readonly direction: MoveDirection;
};

export type AttackAction = {
  readonly kind: "attack";
  readonly targetId: EntityId;
};

export type UseItemAction = {
  readonly kind: "use_item";
  readonly itemId: string;
  readonly target?: ActionTarget;
  readonly direction?: MoveDirection;
};

export type PickupAction = {
  readonly kind: "pickup";
};

export type TalkAction = {
  readonly kind: "talk";
  readonly npcId: EntityId;
};

export type WaitAction = {
  readonly kind: "wait";
};

export type DescendAction = {
  readonly kind: "descend";
};

export type InspectAction = {
  readonly kind: "inspect";
  readonly cell: Position;
};

export type AbortAction = {
  readonly kind: "abort";
};

export type PlayerAction =
  | MoveAction
  | AttackAction
  | UseItemAction
  | PickupAction
  | TalkAction
  | WaitAction
  | DescendAction
  | InspectAction
  | AbortAction;

export type LegalActionResult = {
  readonly status: "legal";
};

export type IllegalActionResult = {
  readonly status: "illegal";
  readonly reason: string;
};

export type ActionLegality = LegalActionResult | IllegalActionResult;

export const LEGAL_ACTION = { status: "legal" } as const satisfies ActionLegality;

export const isActionLegal = (
  result: ActionLegality,
): result is LegalActionResult => result.status === "legal";

export const checkActionLegality = (
  state: GameState,
  action: PlayerAction,
): ActionLegality => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return illegal(`run is terminal (${state.run.terminalStatus})`);
  }

  switch (action.kind) {
    case "move":
      return checkMoveAction(state, action);
    case "attack":
      return checkAttackAction(state, action);
    case "use_item":
      return checkUseItemAction(state, action);
    case "pickup":
      return checkPickupAction(state);
    case "talk":
      return checkTalkAction(state, action);
    case "wait":
      return LEGAL_ACTION;
    case "descend":
      return checkDescendAction(state);
    case "inspect":
      return checkInspectAction(state, action);
    case "abort":
      return LEGAL_ACTION;
  }
};

export const getAvailableActions = (state: GameState): readonly PlayerAction[] => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return [];
  }

  const actions: PlayerAction[] = [];

  for (const { direction } of MOVE_DIRECTIONS) {
    const action = { kind: "move", direction } as const;
    pushIfLegal(actions, state, action);
  }

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "enemy") {
      pushIfLegal(actions, state, {
        kind: "attack",
        targetId: entity.id,
      });
    }
  }

  for (const item of carriedItems(state.player.inventory)) {
    pushIfLegal(actions, state, {
      kind: "use_item",
      itemId: item.itemInstanceId,
    });
  }

  pushIfLegal(actions, state, { kind: "pickup" });

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "npc") {
      pushIfLegal(actions, state, {
        kind: "talk",
        npcId: entity.id,
      });
    }
  }

  pushIfLegal(actions, state, { kind: "wait" });
  pushIfLegal(actions, state, { kind: "descend" });
  actions.push(...availableInspectActions(state));
  pushIfLegal(actions, state, { kind: "abort" });

  return actions;
};

export const destinationForMove = (
  origin: Position,
  direction: MoveDirection,
): Position => {
  const offset = offsetForDirection(direction);

  return {
    x: origin.x + offset.x,
    y: origin.y + offset.y,
  };
};

export const gridFromState = (state: GameState): TileGrid | null => {
  const opaque = state.floor.geometry.opaque;

  if (!isTileGridRecord(opaque)) {
    return null;
  }

  return opaque as unknown as TileGrid;
};

const checkMoveAction = (
  state: GameState,
  action: MoveAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  const destination = destinationForMove(state.player.position, action.direction);

  if (!inBounds(grid, destination)) {
    return illegal(
      `move ${action.direction} leaves the map at (${destination.x}, ${destination.y})`,
    );
  }

  const tile = getTile(grid, destination);

  if (!isWalkableTile(tile)) {
    return illegal(`terrain ${tile.terrain} blocks movement`);
  }

  return LEGAL_ACTION;
};

const checkAttackAction = (
  state: GameState,
  action: AttackAction,
): ActionLegality => {
  const target = state.entities[action.targetId];

  if (target === undefined) {
    return illegal(`attack target ${action.targetId} does not exist`);
  }

  if (target.kind !== "enemy") {
    return illegal(`attack target ${action.targetId} is not an enemy`);
  }

  if (!isAdjacentToPlayer(state, target.position)) {
    return illegal(`attack target ${action.targetId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

const checkUseItemAction = (
  state: GameState,
  action: UseItemAction,
): ActionLegality => {
  if (
    !state.player.inventory.some(
      (slot) => slot?.itemInstanceId === action.itemId,
    )
  ) {
    return illegal(`item ${action.itemId} is not carried`);
  }

  if (action.target === undefined || action.target.kind === "self") {
    return action.direction === undefined ||
      MOVE_DIRECTIONS.some((entry) => entry.direction === action.direction)
      ? LEGAL_ACTION
      : illegal(`unknown use direction ${action.direction}`);
  }

  if (action.target.kind === "entity") {
    return state.entities[action.target.entityId] === undefined
      ? illegal(`target entity ${action.target.entityId} does not exist`)
      : LEGAL_ACTION;
  }

  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  return inBounds(grid, action.target.cell)
    ? LEGAL_ACTION
    : illegal(
        `target cell (${action.target.cell.x}, ${action.target.cell.y}) is outside the map`,
      );
};

const checkPickupAction = (state: GameState): ActionLegality => {
  if (!state.player.inventory.some((slot) => slot === null)) {
    return illegal("inventory is full");
  }

  return sortedEntities(state).some(
    (entity) =>
      entity.kind === "item" &&
      samePosition(entity.position, state.player.position),
  )
    ? LEGAL_ACTION
    : illegal("there is no item here to pick up");
};

const checkTalkAction = (
  state: GameState,
  action: TalkAction,
): ActionLegality => {
  const npc = state.entities[action.npcId];

  if (npc === undefined) {
    return illegal(`npc ${action.npcId} does not exist`);
  }

  if (npc.kind !== "npc") {
    return illegal(`target ${action.npcId} is not an npc`);
  }

  if (!isAdjacentToPlayer(state, npc.position)) {
    return illegal(`npc ${action.npcId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

const checkDescendAction = (state: GameState): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  if (!inBounds(grid, state.player.position)) {
    return illegal(
      `player position (${state.player.position.x}, ${state.player.position.y}) is outside the map`,
    );
  }

  const tile = getTile(grid, state.player.position);

  return tile.terrain === Terrain.StairsDown
    ? LEGAL_ACTION
    : illegal("player is not standing on stairs down");
};

const checkInspectAction = (
  state: GameState,
  action: InspectAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  return inBounds(grid, action.cell)
    ? LEGAL_ACTION
    : illegal(`inspect cell (${action.cell.x}, ${action.cell.y}) is outside the map`);
};

const availableInspectActions = (state: GameState): readonly InspectAction[] => {
  const grid = gridFromState(state);

  if (grid === null) {
    return [];
  }

  const actions: InspectAction[] = [];

  for (let y = 0; y < grid.height; y += 1) {
    for (let x = 0; x < grid.width; x += 1) {
      actions.push({
        kind: "inspect",
        cell: { x, y },
      });
    }
  }

  return actions;
};

const carriedItems = (inventory: readonly InventorySlot[]) =>
  inventory.filter((slot) => slot !== null);

const pushIfLegal = (
  actions: PlayerAction[],
  state: GameState,
  action: PlayerAction,
): void => {
  if (isActionLegal(checkActionLegality(state, action))) {
    actions.push(action);
  }
};

const sortedEntities = (state: GameState): readonly EntityInstance[] =>
  Object.values(state.entities).sort((a, b) => a.id.localeCompare(b.id));

const isAdjacentToPlayer = (state: GameState, position: Position): boolean =>
  chebyshevDistance(state.player.position, position) <= 1;

const samePosition = (a: Position, b: Position): boolean =>
  a.x === b.x && a.y === b.y;

const offsetForDirection = (direction: MoveDirection): Position => {
  const entry = MOVE_DIRECTIONS.find((candidate) => candidate.direction === direction);

  if (entry === undefined) {
    throw new RangeError(`unknown move direction: ${direction}`);
  }

  return entry.offset;
};

const isTileGridRecord = (
  value: SerializableRecord | null,
): value is SerializableRecord => {
  if (value === null) {
    return false;
  }

  const record = value as {
    readonly kind?: unknown;
    readonly width?: unknown;
    readonly height?: unknown;
    readonly tiles?: unknown;
  };

  return (
    record.kind === "tile-grid" &&
    Number.isSafeInteger(record.width) &&
    Number.isSafeInteger(record.height) &&
    Array.isArray(record.tiles)
  );
};

const illegal = (reason: string): IllegalActionResult => ({
  status: "illegal",
  reason,
});

import type { NpcDefinition } from "../../schemas/entities/index.js";

type DialogueTree = NpcDefinition["dialogue"];
type DialogueNode = DialogueTree["nodes"][number];
type DialogueChoice = DialogueNode["choices"][number];
import type {
  EngineLogEventDataByType,
  EntityId,
  GameState,
  NpcEntityInstance,
} from "../state/index.js";
import {
  registerActionResolver,
  step,
  type ActionResolver,
  type ActionResolverResult,
  type PlayerAction,
  type StepOptions,
  type StepResult,
  type TalkAction,
  type TurnEvent,
  type TurnHooks,
} from "../turn/index.js";
import {
  ACTIVE_NODE_KEY,
  BARTER_OPEN_KEY,
  DIALOGUE_FLAGS_KEY,
  getActiveConversation,
  isWorldPaused,
  MERCHANT_STOCK_KEY,
  readDialogueRuntime,
  withNpcDialogueRuntime,
} from "./runtime.js";

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly dialogue_opened: {
      readonly npcId: EntityId;
      readonly nodeId: string;
    };
    readonly dialogue_choice_selected: {
      readonly npcId: EntityId;
      readonly choiceId: string;
      readonly nodeId: string;
    };
    readonly dialogue_ended: {
      readonly npcId: EntityId;
    };
    readonly dialogue_flag_set: {
      readonly npcId: EntityId;
      readonly flag: string;
    };
    readonly barter_opened: {
      readonly npcId: EntityId;
    };
    readonly quest_offer_hook: {
      readonly npcId: EntityId;
      readonly questHookId: string;
    };
  }
}

export type DialogueResolution =
  | {
      readonly state: GameState;
      readonly events: readonly TurnEvent[];
    }
  | {
      readonly illegal: true;
      readonly reason: string;
    };

export type QuestOfferHook = (context: {
  readonly state: GameState;
  readonly npcId: EntityId;
  readonly questHookId: string;
}) => GameState;

let questOfferHook: QuestOfferHook = ({ state }) => state;

export const registerQuestOfferHook = (hook: QuestOfferHook): (() => void) => {
  const previous = questOfferHook;
  questOfferHook = hook;

  return () => {
    if (questOfferHook === hook) {
      questOfferHook = previous;
    }
  };
};

export const getCurrentDialogueNode = (
  state: GameState,
): { readonly npc: NpcEntityInstance; readonly node: DialogueNode } | null => {
  const conversation = getActiveConversation(state);

  if (conversation === null) {
    return null;
  }

  const npc = state.entities[conversation.npcId];

  if (npc?.kind !== "npc") {
    return null;
  }

  const node = findDialogueNode(npc.definition.dialogue, conversation.nodeId);

  return node === null ? null : { npc, node };
};

export const openConversation = (
  state: GameState,
  npcId: EntityId,
): DialogueResolution => {
  const npc = state.entities[npcId];

  if (npc?.kind !== "npc") {
    return illegal(`npc ${npcId} does not exist`);
  }

  if (getActiveConversation(state) !== null) {
    return illegal("a conversation is already active");
  }

  const rootNodeId = npc.definition.dialogue.rootNodeId;
  const nextState = withNpcDialogueRuntime(state, npcId, {
    [ACTIVE_NODE_KEY]: rootNodeId,
    [BARTER_OPEN_KEY]: false,
  });

  return {
    state: nextState,
    events: [
      dialogueEvent(state, "dialogue_opened", {
        npcId,
        nodeId: rootNodeId,
      }),
    ],
  };
};

export const resolveTalkAction: ActionResolver<TalkAction> = (
  state,
  action,
): ActionResolverResult => openConversation(state, action.npcId);

export const resolveEndConversation = (state: GameState): DialogueResolution => {
  const conversation = getActiveConversation(state);

  if (conversation === null) {
    return illegal("no active conversation");
  }

  return closeConversation(state, conversation.npcId);
};

export const resolveDialogueChoice = (
  state: GameState,
  choiceId: string,
): DialogueResolution => {
  const current = getCurrentDialogueNode(state);

  if (current === null) {
    return illegal("no active conversation");
  }

  const choice = current.node.choices.find((candidate) => candidate.id === choiceId);

  if (choice === undefined) {
    return illegal(`unknown dialogue choice ${choiceId}`);
  }

  let nextState = state;
  const events: TurnEvent[] = [
    dialogueEvent(state, "dialogue_choice_selected", {
      npcId: current.npc.id,
      choiceId,
      nodeId: current.node.id,
    }),
  ];

  const flag = parseFlagConsequence(choice);
  if (flag !== null) {
    nextState = setDialogueFlag(nextState, current.npc.id, flag);
    events.push(
      dialogueEvent(state, "dialogue_flag_set", {
        npcId: current.npc.id,
        flag,
      }),
    );
  }

  if (parseBarterConsequence(choice)) {
    nextState = openBarterState(nextState, current.npc);
    events.push(
      dialogueEvent(state, "barter_opened", {
        npcId: current.npc.id,
      }),
    );
  }

  if (choice.questHookId !== null) {
    nextState = questOfferHook({
      state: nextState,
      npcId: current.npc.id,
      questHookId: choice.questHookId,
    });
    events.push(
      dialogueEvent(state, "quest_offer_hook", {
        npcId: current.npc.id,
        questHookId: choice.questHookId,
      }),
    );
  }

  if (choice.nextNodeId !== null) {
    const node = findDialogueNode(current.npc.definition.dialogue, choice.nextNodeId);

    if (node === null) {
      return illegal(`dialogue node ${choice.nextNodeId} does not exist`);
    }

    nextState = withNpcDialogueRuntime(nextState, current.npc.id, {
      [ACTIVE_NODE_KEY]: choice.nextNodeId,
    });
  }

  if (choice.closesDialogue || choice.nextNodeId === null) {
    const closed = closeConversation(nextState, current.npc.id);

    if ("illegal" in closed) {
      return closed;
    }

    return {
      state: closed.state,
      events: [...events, ...closed.events],
    };
  }

  return {
    state: nextState,
    events,
  };
};

export const freezeTurnCount = (state: GameState, turn: number): GameState => ({
  ...state,
  run: {
    ...state.run,
    turn,
  },
});

export const dialogueTurnHooks = (): TurnHooks => ({
  actorTurn: ({ state, actor }) =>
    isWorldPaused(state) && actor.kind === "enemy" ? state : state,
  ticks: {
    damageOverTime: ({ state }) => (isWorldPaused(state) ? state : state),
    durations: ({ state }) => (isWorldPaused(state) ? state : state),
    hunger: ({ state }) => (isWorldPaused(state) ? state : state),
    regen: ({ state }) => (isWorldPaused(state) ? state : state),
  },
});

export const stepWithDialoguePause = (
  state: GameState,
  action: PlayerAction,
  options: StepOptions = {},
): StepResult => {
  const turnBefore = state.run.turn;
  const mergedHooks = mergeDialogueHooks(options.hooks);
  const result = step(state, action, { ...options, hooks: mergedHooks });

  if (shouldFreezeTurn(state, result.state, action)) {
    return {
      ...result,
      state: freezeTurnCount(result.state, turnBefore),
    };
  }

  return result;
};

export const registerNpcDialogueHooks = (): (() => void) =>
  registerActionResolver("talk", resolveTalkAction);

export const unregisterNpcDialogueHooks = registerNpcDialogueHooks();

const shouldFreezeTurn = (
  before: GameState,
  after: GameState,
  action: PlayerAction,
): boolean =>
  isWorldPaused(before) || isWorldPaused(after) || action.kind === "talk";

const mergeDialogueHooks = (hooks: TurnHooks | undefined): TurnHooks => {
  return {
    actorTurn: ({ state, actor, action }) => {
      if (isWorldPaused(state) && actor.kind === "enemy") {
        return state;
      }

      return hooks?.actorTurn?.({ state, actor, action }) ?? state;
    },
    ticks: {
      damageOverTime: (context) =>
        isWorldPaused(context.state)
          ? context.state
          : (hooks?.ticks?.damageOverTime?.(context) ?? context.state),
      durations: (context) =>
        isWorldPaused(context.state)
          ? context.state
          : (hooks?.ticks?.durations?.(context) ?? context.state),
      hunger: (context) =>
        isWorldPaused(context.state)
          ? context.state
          : (hooks?.ticks?.hunger?.(context) ?? context.state),
      regen: (context) =>
        isWorldPaused(context.state)
          ? context.state
          : (hooks?.ticks?.regen?.(context) ?? context.state),
    },
  };
};

const closeConversation = (
  state: GameState,
  npcId: EntityId,
): DialogueResolution => {
  const npc = state.entities[npcId];

  if (npc?.kind !== "npc") {
    return illegal(`npc ${npcId} does not exist`);
  }

  return {
    state: withNpcDialogueRuntime(state, npcId, {
      [ACTIVE_NODE_KEY]: "",
      [BARTER_OPEN_KEY]: false,
    }),
    events: [
      dialogueEvent(state, "dialogue_ended", {
        npcId,
      }),
    ],
  };
};

const openBarterState = (state: GameState, npc: NpcEntityInstance): GameState => {
  const runtime = readDialogueRuntime(npc);
  const stock =
    runtime[MERCHANT_STOCK_KEY] ??
    [...npc.definition.merchantInventoryItemIds];

  return withNpcDialogueRuntime(state, npc.id, {
    [BARTER_OPEN_KEY]: true,
    [MERCHANT_STOCK_KEY]: stock,
  });
};

const setDialogueFlag = (
  state: GameState,
  npcId: EntityId,
  flag: string,
): GameState => {
  const npc = state.entities[npcId];

  if (npc?.kind !== "npc") {
    return state;
  }

  const runtime = readDialogueRuntime(npc);
  const existing = runtime[DIALOGUE_FLAGS_KEY] ?? {};

  return withNpcDialogueRuntime(state, npcId, {
    [DIALOGUE_FLAGS_KEY]: {
      ...existing,
      [flag]: true,
    },
  });
};

const findDialogueNode = (
  tree: DialogueTree,
  nodeId: string,
): DialogueNode | null =>
  tree.nodes.find((node) => node.id === nodeId) ?? null;

const parseFlagConsequence = (choice: DialogueChoice): string | null => {
  const prefix = "flag:";

  return choice.id.startsWith(prefix) ? choice.id.slice(prefix.length) : null;
};

const parseBarterConsequence = (choice: DialogueChoice): boolean =>
  choice.id === "barter" || choice.id.startsWith("barter:");

const dialogueEvent = <Type extends keyof EngineLogEventDataByType>(
  state: GameState,
  type: Type,
  data: EngineLogEventDataByType[Type],
): TurnEvent =>
  ({
    turn: state.run.turn,
    type,
    data,
  }) as TurnEvent;

const illegal = (reason: string): DialogueResolution => ({
  illegal: true,
  reason,
});

import { config } from "../../config/index.js";
import type { ItemDefinition } from "../../schemas/entities/index.js";
import {
  addToInventory,
  canAddQuantityToInventory,
  findInventorySlotIndex,
  removeFromInventory,
  type InventoryOperationResult,
} from "../systems/inventory.js";
import type {
  EntityId,
  GameState,
  NpcEntityInstance,
  PlayerItemStack,
} from "../state/index.js";
import type { TurnEvent } from "../turn/index.js";
import { getActiveConversation, isBarterOpen, readDialogueRuntime, withNpcDialogueRuntime } from "./runtime.js";

export type BarterCatalog = {
  readonly resolve: (definitionId: string) => ItemDefinition | null;
  readonly coinDefinition: ItemDefinition;
};

export type BarterRefusalReason =
  | "insufficient_coin"
  | "inventory_full"
  | "item_not_carried"
  | "item_not_in_stock"
  | "barter_closed"
  | "no_active_conversation";

export type BarterResolution =
  | {
      readonly state: GameState;
      readonly events: readonly TurnEvent[];
    }
  | {
      readonly refused: true;
      readonly reason: BarterRefusalReason;
      readonly message: string;
    };

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly barter_buy: {
      readonly npcId: EntityId;
      readonly definitionId: string;
      readonly price: number;
      readonly itemInstanceId: string;
    };
    readonly barter_sell: {
      readonly npcId: EntityId;
      readonly definitionId: string;
      readonly price: number;
      readonly itemInstanceId: string;
    };
  }
}

const INSUFFICIENT_COIN_MESSAGE = "You don't have enough coin.";
const INVENTORY_FULL_MESSAGE = "Your pack is full.";
const ITEM_NOT_CARRIED_MESSAGE = "That item isn't in your pack.";
const ITEM_NOT_IN_STOCK_MESSAGE = "The merchant doesn't have that.";
const BARTER_CLOSED_MESSAGE = "Barter isn't open.";
const NO_CONVERSATION_MESSAGE = "No one is trading with you.";

export const merchantBuyPrice = (baseValue: number): number =>
  Math.max(1, Math.round(baseValue * config.itemsEconomy.merchantMultipliers.buy));

export const merchantSellPrice = (
  state: GameState,
  npcId: EntityId,
  definitionId: string,
  baseValue: number,
): number => {
  const multiplier = sellMultiplierFor(state, npcId, definitionId);

  return Math.max(1, Math.round(baseValue * multiplier));
};

export const sellMultiplierFor = (
  state: GameState,
  npcId: EntityId,
  definitionId: string,
): number => {
  const { min, max } = config.itemsEconomy.merchantMultipliers.sell;
  const basis = `${state.rng.rootSeed}|${npcId}|${definitionId}|sell`;
  let hash = 0;

  for (let index = 0; index < basis.length; index += 1) {
    hash = (hash * 31 + basis.charCodeAt(index)) >>> 0;
  }

  const span = max - min;
  const step = hash % 1_001;
  const multiplier = min + (step / 1_000) * span;

  return Math.round(multiplier * 1_000) / 1_000;
};

export const countPlayerCoinValue = (state: GameState): number => {
  let total = 0;

  for (const slot of state.player.inventory) {
    if (slot === null || slot.definition.kind !== "coin") {
      continue;
    }

    total += slot.quantity * slot.definition.value.coin;
  }

  return total;
};

export const computePlayerWealth = (state: GameState): number => {
  let total = countPlayerCoinValue(state);

  for (const slot of state.player.inventory) {
    if (slot === null || slot.definition.kind === "coin") {
      continue;
    }

    total += slot.quantity * slot.definition.value.coin;
  }

  return total;
};

export const buyFromMerchant = (
  state: GameState,
  catalog: BarterCatalog,
  definitionId: string,
): BarterResolution => {
  const merchant = activeMerchant(state);

  if (merchant === null) {
    return refuse("no_active_conversation", NO_CONVERSATION_MESSAGE);
  }

  if (!isBarterOpen(state)) {
    return refuse("barter_closed", BARTER_CLOSED_MESSAGE);
  }

  const stock = merchantStock(merchant);
  const stockIndex = stock.indexOf(definitionId);

  if (stockIndex === -1) {
    return refuse("item_not_in_stock", ITEM_NOT_IN_STOCK_MESSAGE);
  }

  const definition = catalog.resolve(definitionId);

  if (definition === null) {
    return refuse("item_not_in_stock", ITEM_NOT_IN_STOCK_MESSAGE);
  }

  const price = merchantSellPrice(state, merchant.id, definitionId, definition.value.coin);

  if (countPlayerCoinValue(state) < price) {
    return refuse("insufficient_coin", INSUFFICIENT_COIN_MESSAGE);
  }

  if (!canAddQuantityToInventory(state.player.inventory, definition, 1)) {
    return refuse("inventory_full", INVENTORY_FULL_MESSAGE);
  }

  const paid = removeCoinValue(state, price);

  if ("refused" in paid) {
    return paid;
  }

  const stack: PlayerItemStack = {
    itemInstanceId: `${merchant.id}:${definitionId}:buy`,
    definition,
    quantity: 1,
    identified: true,
  };
  const added = addToInventory(paid.state, stack);

  if ("illegal" in added) {
    return refuse("inventory_full", INVENTORY_FULL_MESSAGE);
  }

  const nextStock = [...stock];
  nextStock.splice(stockIndex, 1);

  const nextState = withNpcDialogueRuntime(added.state, merchant.id, {
    merchantStockIds: nextStock,
  });

  return {
    state: nextState,
    events: [
      barterEvent(state, "barter_buy", {
        npcId: merchant.id,
        definitionId,
        price,
        itemInstanceId: stack.itemInstanceId,
      }),
    ],
  };
};

export const sellToMerchant = (
  state: GameState,
  catalog: BarterCatalog,
  itemInstanceId: string,
): BarterResolution => {
  const merchant = activeMerchant(state);

  if (merchant === null) {
    return refuse("no_active_conversation", NO_CONVERSATION_MESSAGE);
  }

  if (!isBarterOpen(state)) {
    return refuse("barter_closed", BARTER_CLOSED_MESSAGE);
  }

  const slotIndex = findInventorySlotIndex(state.player.inventory, itemInstanceId);

  if (slotIndex === null) {
    return refuse("item_not_carried", ITEM_NOT_CARRIED_MESSAGE);
  }

  const slot = state.player.inventory[slotIndex];

  if (slot === null || slot === undefined || slot.definition.kind === "coin") {
    return refuse("item_not_carried", ITEM_NOT_CARRIED_MESSAGE);
  }

  const soldItem = slot;
  const price = merchantBuyPrice(soldItem.definition.value.coin);
  const removed = removeFromInventory(state, itemInstanceId, 1);

  if ("illegal" in removed) {
    return refuse("item_not_carried", ITEM_NOT_CARRIED_MESSAGE);
  }

  const credited = addCoinValue(removed.state, price, catalog.coinDefinition);

  if ("refused" in credited || "illegal" in credited) {
    return "refused" in credited
      ? credited
      : refuse("item_not_carried", ITEM_NOT_CARRIED_MESSAGE);
  }

  const stock = merchantStock(merchant);
  const nextStock = [...stock, soldItem.definition.id];

  return {
    state: withNpcDialogueRuntime(credited.state, merchant.id, {
      merchantStockIds: nextStock,
    }),
    events: [
      barterEvent(state, "barter_sell", {
        npcId: merchant.id,
        definitionId: soldItem.definition.id,
        price,
        itemInstanceId,
      }),
    ],
  };
};

export const computeBarterEconomyTotal = (
  state: GameState,
  catalog: BarterCatalog,
): number => {
  let total = countPlayerCoinValue(state);

  for (const slot of state.player.inventory) {
    if (slot === null || slot.definition.kind === "coin") {
      continue;
    }

    total += slot.quantity * slot.definition.value.coin;
  }

  for (const entity of Object.values(state.entities)) {
    if (entity.kind !== "npc") {
      continue;
    }

    const stock = merchantStock(entity);

    for (const definitionId of stock) {
      const definition = catalog.resolve(definitionId);

      if (definition !== null) {
        total += definition.value.coin;
      }
    }
  }

  return total;
};

const MERCHANT_STOCK_KEY = "merchantStockIds" as const;

const activeMerchant = (state: GameState): NpcEntityInstance | null => {
  const conversation = getActiveConversation(state);

  if (conversation === null) {
    return null;
  }

  const npc = state.entities[conversation.npcId];

  return npc?.kind === "npc" ? npc : null;
};

const merchantStock = (npc: NpcEntityInstance): readonly string[] =>
  readDialogueRuntime(npc)[MERCHANT_STOCK_KEY] ??
  npc.definition.merchantInventoryItemIds;

const removeCoinValue = (
  state: GameState,
  amount: number,
): BarterResolution | { readonly state: GameState } => {
  let remaining = amount;
  let nextState = state;

  for (const slot of state.player.inventory) {
    if (slot === null || slot.definition.kind !== "coin" || remaining <= 0) {
      continue;
    }

    const slotValue = slot.quantity * slot.definition.value.coin;

    if (slotValue <= remaining) {
      const removed = removeFromInventory(nextState, slot.itemInstanceId, slot.quantity);

      if ("illegal" in removed) {
        return refuse("insufficient_coin", INSUFFICIENT_COIN_MESSAGE);
      }

      nextState = removed.state;
      remaining -= slotValue;
      continue;
    }

    const unitsNeeded = Math.ceil(remaining / slot.definition.value.coin);
    const removed = removeFromInventory(nextState, slot.itemInstanceId, unitsNeeded);

    if ("illegal" in removed) {
      return refuse("insufficient_coin", INSUFFICIENT_COIN_MESSAGE);
    }

    nextState = removed.state;
    remaining = 0;
  }

  if (remaining > 0) {
    return refuse("insufficient_coin", INSUFFICIENT_COIN_MESSAGE);
  }

  return { state: nextState };
};

const addCoinValue = (
  state: GameState,
  amount: number,
  fallbackCoinDefinition: ItemDefinition,
): BarterResolution | InventoryOperationResult => {
  const coinDefinition = findCoinDefinition(state) ?? fallbackCoinDefinition;

  const unitValue = coinDefinition.value.coin;

  if (unitValue < 1 || amount % unitValue !== 0) {
    return refuse("insufficient_coin", INSUFFICIENT_COIN_MESSAGE);
  }

  const stack: PlayerItemStack = {
    itemInstanceId: `coin#barter-${amount}`,
    definition: coinDefinition,
    quantity: amount / unitValue,
    identified: true,
  };

  return addToInventory(state, stack);
};

const findCoinDefinition = (state: GameState): ItemDefinition | null => {
  for (const slot of state.player.inventory) {
    if (slot?.definition.kind === "coin") {
      return slot.definition;
    }
  }

  return null;
};

const refuse = (
  reason: BarterRefusalReason,
  message: string,
): BarterResolution => ({
  refused: true,
  reason,
  message,
});

