const featureAtPosition = (
  state: GameState,
  position: Position,
  featureId: string,
): boolean => {
  const opaque = state.floor.geometry.opaque as FloorRuntimeOpaque | null;
  const features = opaque?.knowledge?.decorativeFeatures ?? [];

  return features.some((feature) => {
    const id = feature.id;
    const x = feature.x;
    const y = feature.y;

    return (
      id === featureId &&
      typeof x === "number" &&
      typeof y === "number" &&
      x === position.x &&
      y === position.y
    );
  });
