import { createElement } from "react";
import { renderToStaticMarkup } from "react-dom/server";
import { describe, expect, it } from "vitest";

import { createInitialState, type GameState } from "@engine/state";

import { HudFrame } from "./Hud";
import { createHudViewModel, type HudViewModel } from "./model";

describe("Hud", () => {
  it("renders depth, turn, HP number plus bar, fullness, level XP, and shaped status chips", () => {
    const model = createHudViewModel(createHudFixtureState());
    const markup = renderHud(model);

    expect(model.depth.value).toBe(3);
    expect(model.turn.value).toBe(17);
    expect(model.hp).toMatchObject({
      current: 11,
      max: 24,
    });
    expect(model.fullness).toMatchObject({
      current: 64,
      max: 100,
    });
    expect(model.levelXp).toMatchObject({
      level: 2,
      xp: 5,
    });
    expect(model.statuses).toEqual([
      {
        status: "poison",
        label: "Poison",
        duration: 3,
        shape: "diamond",
      },
      {
        status: "shield",
        label: "Shield",
        duration: 4,
        shape: "square",
      },
    ]);
    expect(markup).toContain('role="meter"');
    expect(markup).toContain('data-status="poison"');
    expect(markup).toContain('data-status-shape="diamond"');
    expect(markup).toContain('data-status="shield"');
    expect(markup).toContain('data-status-shape="square"');
  });

  it("pulses HUD fields only when player event metadata marks them changed since the previous render", () => {
    const base = createHudFixtureState();
    const before = createHudViewModel(base);
    const levelUp = createHudViewModel(withLevelUpPulse(base), before.cursor);
    const noHudChange = createHudViewModel(
      withNonHudEvent(base),
      before.cursor,
    );
    const firstRender = createHudViewModel(withLevelUpPulse(base));

    expect(levelUp.hp.pulse).toBe(true);
    expect(levelUp.levelXp.pulse).toBe(true);
    expect(levelUp.fullness.pulse).toBe(false);
    expect(levelUp.depth.pulse).toBe(false);
    expect(levelUp.turn.pulse).toBe(false);

    expect(noHudChange.hp.pulse).toBe(false);
    expect(noHudChange.levelXp.pulse).toBe(false);
    expect(firstRender.hp.pulse).toBe(false);
    expect(renderHud(levelUp)).toContain('data-pulse="true"');
  });
});

const renderHud = (model: HudViewModel): string =>
  renderToStaticMarkup(createElement(HudFrame, { model }));

const createHudFixtureState = (): GameState => ({
  ...createInitialState("hud-fixture"),
  run: {
    ...createInitialState("hud-fixture").run,
    depth: 3,
    turn: 17,
  },
  floor: {
    ...createInitialState("hud-fixture").floor,
    depth: 3,
  },
  player: {
    ...createInitialState("hud-fixture").player,
    hp: {
      current: 11,
      max: 24,
    },
    fullness: {
      current: 64,
      max: 100,
    },
    level: 2,
    xp: 5,
    statuses: [
      { status: "poison", duration: 3 },
      { status: "shield", duration: 4 },
    ],
  },
});

const withLevelUpPulse = (state: GameState): GameState => ({
  ...state,
  player: {
    ...state.player,
    hp: {
      current: 15,
      max: 28,
    },
    level: 3,
    xp: 1,
  },
  log: [
    ...state.log,
    {
      turn: state.run.turn,
      type: "level_up",
      data: {
        actorId: "player",
        levelBefore: 2,
        levelAfter: 3,
        xpBefore: 13,
        xpAfter: 1,
        xpToNextLevel: 24,
        maxHpBefore: 24,
        maxHpAfter: 28,
        currentHpBefore: 11,
        currentHpAfter: 15,
        hud: {
          pulse: true,
          fields: ["level", "xp", "hp", "maxHp", "attack", "defense"],
        },
      },
    } as GameState["log"][number],
  ],
});

const withNonHudEvent = (state: GameState): GameState => ({
  ...state,
  log: [
    ...state.log,
    {
      turn: state.run.turn,
      type: "moved",
      data: {
        actorId: "player",
        direction: "east",
        from: { x: 1, y: 1 },
        to: { x: 2, y: 1 },
      },
    } as GameState["log"][number],
  ],
});

.region {
  display: grid;
  min-height: 0;
  overflow: hidden;
  border: 1px solid var(--gg-border);
  border-radius: 8px;
  background: var(--gg-surface);
  color: var(--gg-text);
}

.panel {
  display: grid;
  grid-template-rows: auto auto 1fr;
  gap: 0.55rem;
  min-width: 0;
  min-height: 0;
  padding: 0.7rem;
}

.empty {
  display: grid;
  min-height: 6rem;
  place-items: center;
  color: var(--gg-muted);
  font-size: 0.82rem;
}

.topline {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.5rem;
}

.stat,
.meter,
.levelXp {
  min-width: 0;
  border: 1px solid rgba(255, 255, 255, 0.07);
  border-radius: 6px;
  background: #10151d;
}

.stat {
  display: grid;
  grid-template-columns: auto 1fr;
  align-items: baseline;
  gap: 0.45rem;
  padding: 0.4rem 0.5rem;
}

.meter {
  display: grid;
  gap: 0.35rem;
  padding: 0.5rem;
}

.meterHeader {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 0.5rem;
  min-width: 0;
}

.label {
  color: var(--gg-muted);
  font-size: 0.64rem;
  letter-spacing: 0;
  line-height: 1;
  text-transform: uppercase;
}

.value {
  min-width: 0;
  color: var(--gg-text);
  font-size: 0.94rem;
  font-weight: 800;
  letter-spacing: 0;
  line-height: 1;
  text-align: right;
}

.bar {
  height: 0.48rem;
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 999px;
  background: #080b10;
}

.barFill {
  display: block;
  height: 100%;
  border-radius: inherit;
  background: linear-gradient(90deg, #79d39f, #d9c96c);
}

.fullnessFill {
  background: linear-gradient(90deg, #6ea8fe, #9ed0ff);
}

.levelXp {
  display: grid;
  grid-template-columns: 1fr 1fr;
  align-items: center;
  gap: 0.5rem;
  padding: 0.52rem;
}

.levelValue {
  color: #ffe680;
}

.xpValue {
  color: #9ed0ff;
}

.statuses {
  display: flex;
  min-width: 0;
  flex-wrap: wrap;
  align-content: start;
  gap: 0.35rem;
}

.chip {
  display: inline-flex;
  align-items: center;
  min-width: 0;
  gap: 0.32rem;
  border: 1px solid rgba(255, 255, 255, 0.11);
  border-radius: 999px;
  background: #0f141b;
  color: var(--gg-text);
  font-size: 0.69rem;
  line-height: 1;
  padding: 0.28rem 0.44rem;
}

.chipIcon {
  position: relative;
  flex: 0 0 auto;
  width: 0.58rem;
  height: 0.58rem;
  color: #d6deea;
}

.chipIcon::before,
.chipIcon::after {
  position: absolute;
  content: "";
}

.shapeCircle::before {
  inset: 0.08rem;
  border: 1px solid currentColor;
  border-radius: 999px;
}

.shapeDiamond::before {
  inset: 0.12rem;
  border: 1px solid currentColor;
  transform: rotate(45deg);
}

.shapeSquare::before {
  inset: 0.1rem;
  border: 1px solid currentColor;
  border-radius: 1px;
}

.shapeDot::before {
  inset: 0.17rem;
  border-radius: 999px;
  background: currentColor;
}

.shapeTriangle::before {
  inset: 0.08rem;
  background: currentColor;
  clip-path: polygon(50% 0, 100% 100%, 0 100%);
}

.shapeBar::before {
  top: 0.25rem;
  right: 0.03rem;
  left: 0.03rem;
  height: 0.08rem;
  background: currentColor;
}

.shapeCross::before,
.shapeCross::after {
  top: 0.25rem;
  right: 0.04rem;
  left: 0.04rem;
  height: 0.08rem;
  background: currentColor;
}

.shapeCross::before {
  transform: rotate(45deg);
}

.shapeCross::after {
  transform: rotate(-45deg);
}

.chipDuration {
  color: var(--gg-muted);
}

.noStatus {
  color: var(--gg-muted);
}

.pulse {
  animation: gg-hud-pulse 520ms ease-out;
}

@keyframes gg-hud-pulse {
  0% {
    border-color: rgba(255, 230, 128, 0.86);
    box-shadow: 0 0 0 0 rgba(255, 230, 128, 0.34);
  }
  100% {
    border-color: rgba(255, 255, 255, 0.07);
    box-shadow: 0 0 0 0.55rem rgba(255, 230, 128, 0);
  }
}

